args.query:
SELECT issueid__c AS issue_id, COUNT(*) AS cnt
FROM "Case"
WHERE TRIM(BOTH FROM orderitemid__c) IN (
  SELECT TRIM(BOTH FROM Id) FROM (
    SELECT Id FROM (
      SELECT Id FROM public."Case" LIMIT 0
    ) t0
  ) t1
)
LIMIT 0;

